import * as React from "react";

import { Badge } from "../badge";
import { Button } from "../button";
import { cn } from "../utils/cn";

/* -------------------------------------------------------------------------- */
/*  FilterBar                                                                 */
/* -------------------------------------------------------------------------- */

type FilterBarProps = {
  children: React.ReactNode;
  /** Number of currently active (non-default) filters. */
  activeFilterCount?: number;
  /** Called when the user clicks "Clear filters". */
  onClearAll?: () => void;
  /** Called when the user clicks the refresh/sync button. */
  onRefresh?: () => void;
  /** Whether to show a loading indicator. */
  loading?: boolean;
  /** Whether to show the refresh button. Defaults to true. */
  showRefresh?: boolean;
  /** Whether to show the toggle-filters button (mobile expand). Defaults to true. */
  showFilterToggle?: boolean;
  className?: string;
};

/**
 * Horizontal filter bar matching the Vue V2 FiltersV2 layout.
 *
 * Two-column layout:
 * - Left section (`FilterBarFilters`): filter trigger buttons, search, etc.
 * - Right section (`FilterBarActions`): clear, refresh, toggle buttons.
 *
 * The actions toolbar (clear / refresh / toggle) is rendered inline on the
 * right side, matching the Vue `c-issue-filters__actions` layout.
 */
function FilterBar({
  children,
  activeFilterCount = 0,
  onClearAll,
  onRefresh,
  loading = false,
  showRefresh = true,
  showFilterToggle = true,
  className,
}: FilterBarProps) {
  const [expanded, setExpanded] = React.useState(false);

  return (
    <div data-slot="filter-bar" className={cn("px-4 py-3", className)}>
      <div className="flex items-start gap-3 flex-wrap">
        {/* Filter controls (left) + actions (right) via context */}
        <FilterBarContext.Provider value={{ expanded }}>
          {children}
        </FilterBarContext.Provider>

        {/* Actions section (right-aligned) — Vue: c-issue-filters__actions */}
        {(onClearAll || showRefresh || showFilterToggle) && (
          <div
            data-slot="filter-bar-toolbar"
            className="ml-auto flex items-center gap-2"
          >
            {onClearAll && (
              <Button
                variant="text"
                color="primary"
                size="md"
                onClick={onClearAll}
                data-slot="filter-bar-clear"
                className="h-[44px] px-2 text-base font-normal normal-case"
              >
                Clear
                <span className="hidden xl:inline pl-0.5">filters</span>
              </Button>
            )}

            {showRefresh && onRefresh && (
              <Button
                variant="solid"
                color="default"
                size="md"
                onClick={onRefresh}
                data-slot="filter-bar-refresh"
                className="h-[44px] min-w-[44px] bg-brand-primary-100 text-brand-primary-600"
                aria-label="Refresh data"
              >
                <RefreshIcon className="size-5" />
              </Button>
            )}

            {showFilterToggle && (
              <Button
                variant="solid"
                color="default"
                size="md"
                onClick={() => setExpanded((prev) => !prev)}
                data-slot="filter-bar-toggle"
                className={cn(
                  "h-[44px] bg-brand-primary-100 text-brand-primary-600 text-base font-medium normal-case",
                  expanded && "border-brand-primary-600",
                )}
              >
                <FilterIcon className="size-4 mr-1" />
                Filters
                {activeFilterCount > 0 && (
                  <Badge
                    variant="default"
                    size="sm"
                    className="ml-2 bg-[#936bff] text-white rounded-sm"
                  >
                    {activeFilterCount}
                  </Badge>
                )}
              </Button>
            )}

            {loading && (
              <span
                data-slot="filter-bar-loading"
                className="ml-1 mt-0.5 inline-block size-5 animate-spin rounded-full border-2 border-primary border-t-transparent"
                role="status"
                aria-label="Loading"
              />
            )}
          </div>
        )}
      </div>
    </div>
  );
}

/* -------------------------------------------------------------------------- */
/*  Context                                                                   */
/* -------------------------------------------------------------------------- */

type FilterBarContextValue = {
  expanded: boolean;
};

const FilterBarContext = React.createContext<FilterBarContextValue>({
  expanded: false,
});

function useFilterBarContext() {
  return React.useContext(FilterBarContext);
}

/* -------------------------------------------------------------------------- */
/*  FilterBarFilters (left section — "c-issue-filters__items")                */
/* -------------------------------------------------------------------------- */

type FilterBarFiltersProps = {
  children: React.ReactNode;
  className?: string;
};

/**
 * Left-aligned filter controls section matching Vue's `c-issue-filters__items`.
 *
 * Contains filter triggers, search, download, etc.
 */
function FilterBarFilters({ children, className }: FilterBarFiltersProps) {
  return (
    <div
      data-slot="filter-bar-filters"
      className={cn("flex flex-1 items-center gap-2 flex-wrap", className)}
    >
      {children}
    </div>
  );
}

/* -------------------------------------------------------------------------- */
/*  FilterBarSection (generic group within filters)                           */
/* -------------------------------------------------------------------------- */

type FilterBarSectionProps = {
  children: React.ReactNode;
  className?: string;
};

/**
 * Groups filter controls within a FilterBar.
 */
function FilterBarSection({ children, className }: FilterBarSectionProps) {
  return (
    <div
      data-slot="filter-bar-section"
      className={cn("flex items-center gap-2", className)}
    >
      {children}
    </div>
  );
}

/* -------------------------------------------------------------------------- */
/*  FilterBarActions (right section — "c-issue-filters__actions")             */
/* -------------------------------------------------------------------------- */

type FilterBarActionsProps = {
  children: React.ReactNode;
  className?: string;
};

/**
 * Right-aligned actions (download, search, etc.) matching Vue's
 * `c-issue-filters__actions` section.
 */
function FilterBarActions({ children, className }: FilterBarActionsProps) {
  return (
    <div
      data-slot="filter-bar-actions"
      className={cn("ml-auto flex items-center gap-2", className)}
    >
      {children}
    </div>
  );
}

/* -------------------------------------------------------------------------- */
/*  FilterBarChips (active filter chips row)                                  */
/* -------------------------------------------------------------------------- */

type FilterBarChipsProps = {
  children: React.ReactNode;
  className?: string;
};

/**
 * Row of active-filter chips with remove capability, rendered below the main
 * filter controls.
 */
function FilterBarChips({ children, className }: FilterBarChipsProps) {
  return (
    <div
      data-slot="filter-bar-chips"
      className={cn("mt-2 flex items-center gap-1.5 flex-wrap", className)}
    >
      {children}
    </div>
  );
}

/* -------------------------------------------------------------------------- */
/*  Inline SVG icons (matching Vue mdi-cached / mdi-filter-variant)           */
/* -------------------------------------------------------------------------- */

function RefreshIcon(props: React.ComponentProps<"svg">) {
  return (
    <svg viewBox="0 0 24 24" fill="currentColor" {...props}>
      {/* mdi-cached (sync) icon path */}
      <path d="M19 8l-4 4h3c0 3.31-2.69 6-6 6-1.01 0-1.97-.25-2.8-.7l-1.46 1.46A7.93 7.93 0 0 0 12 20c4.42 0 8-3.58 8-8h3l-4-4zM6 12c0-3.31 2.69-6 6-6 1.01 0 1.97.25 2.8.7l1.46-1.46A7.93 7.93 0 0 0 12 4c-4.42 0-8 3.58-8 8H1l4 4 4-4H6z" />
    </svg>
  );
}

function FilterIcon(props: React.ComponentProps<"svg">) {
  return (
    <svg viewBox="0 0 24 24" fill="currentColor" {...props}>
      {/* mdi-filter-variant icon path */}
      <path d="M6 13h12v-2H6M3 6v2h18V6M10 18h4v-2h-4v2z" />
    </svg>
  );
}

/* -------------------------------------------------------------------------- */
/*  Exports                                                                   */
/* -------------------------------------------------------------------------- */

export {
  FilterBar,
  FilterBarFilters,
  FilterBarSection,
  FilterBarActions,
  FilterBarChips,
  useFilterBarContext,
};
export type {
  FilterBarProps,
  FilterBarFiltersProps,
  FilterBarSectionProps,
  FilterBarActionsProps,
  FilterBarChipsProps,
};
